// Generator for docs/TEST-DISPLAY-MAP.md — the test → fixture lookup.
//
// Answers "which dataset do I load to see a visible flag for test X" during
// the visual walk. The output doc is regenerated by this script alone — never
// hand-edited (a hand-edit gets clobbered on the next regen).
//
// Run:        node scripts/build-test-display-map.mjs
// Freshness:  node scripts/build-test-display-map.mjs --check
//             (regenerates in memory, diffs table/legend/notes against the
//              committed doc ignoring the provenance block; exits non-zero if
//              they differ. No file write.)
//
// Sources (all via the shared data module test/batch-fixtures.mjs + src/):
//   CODE TEST NAME — TEST_MECHANISM keys (src/constants/mechanisms.js)
//   UI NAME        — DISPLAY_NAMES (same file)
//   CLUSTER        — Title-case §3 heading per TEST_MECHANISM[name]'s key
//   FIRES ON       — presence from live batch result.flag (HIGH/MOD) per test
//                    per fixture, which natively includes on-screen acknowledged
//                    fires; the credited-vs-(ack) mark comes from cross-
//                    referencing the shared EXPECTED allow-sets.
//
// dataType routing goes through the shared ASSAY_DATATYPE_MAP (survey→ordinal,
// genomics→count) — the same routing the validator uses. A prior hand-rolled
// ternary here mis-routed DS14 (ran tests that should N/A under ordinal) and
// DS11 (continuous not count); centralising the routing removed that drift.

import { readFileSync, writeFileSync } from 'fs';
import { join } from 'path';
import { execSync } from 'child_process';

globalThis.requestAnimationFrame = (cb) => setTimeout(cb, 0);

const CHECK = process.argv.includes('--check');
const OUT_PATH = 'docs/TEST-DISPLAY-MAP.md';
const FIXTURES_DIR = 'test/fixtures';

const Papa = await import('papaparse');
const { extractAnalysisInputs, runFullAnalysis } = await import('../src/analysis/engine.js');
const { detectVST } = await import('../src/stats/vst.js');
const { inferRoles } = await import('../src/import/roles.js');
const { forwardFill, preprocessRaw, detectHeaderRows } = await import('../src/import/parser.js');
const { detectLongFormat } = await import('../src/import/longFormat.js');
const { suggestRowSemantics } = await import('../src/import/rowSemantics.js');
const { DISPLAY_NAMES, TEST_MECHANISM, MECHANISM_ORDER } = await import('../src/constants/mechanisms.js');
const { EXPECTED, FIXTURES, ASSAY_DATATYPE_MAP } = await import('../test/batch-fixtures.mjs');

// Title-case cluster display names — the §3 on-screen headings. Distinct from
// MECHANISMS[k].label (sentence case); the lookup doc uses Title Case.
const CLUSTER_TITLE = {
  copied:    'Copy, Paste, Edit',
  digits:    'Unusual Digits',
  shapes:    'Distribution Shapes',
  replicate: 'Cross-Replicate Comparisons',
  group:     'Cross-Condition Comparisons',
};

const SHORT = { HIGH: 'HIGH', MODERATE: 'MOD' };

// ── Run the live batch; collect r.flag per test per fixture ──
const liveFlags = Object.fromEntries(Object.keys(TEST_MECHANISM).map(t => [t, {}]));
for (const [file, key, assay] of FIXTURES) {
  if (!CHECK) process.stderr.write(`  ${key}…`);
  const csv = readFileSync(join(FIXTURES_DIR, file), 'utf-8');
  let raw = Papa.default.parse(csv, { skipEmptyLines: true }).data;
  raw = preprocessRaw(raw).rows;
  const headerRows = detectHeaderRows(raw);
  const condPerCol = headerRows >= 2 ? forwardFill(raw[0]) : null;
  const headers = raw[headerRows - 1];
  const data = raw.slice(headerRows);
  const roles = inferRoles(data, headers, condPerCol);
  const { matrix, rawMatrix, condCtx } = extractAnalysisInputs({
    data, roles, condPerCol, zeroAsMissing: false,
  });
  const vst = detectVST(matrix, assay);
  // Shared routing — identical to validate-batch.mjs.
  const dataType = ASSAY_DATATYPE_MAP[assay] || 'continuous';
  const lfDet = detectLongFormat(headers, data);
  const rowSemantics = suggestRowSemantics({ assay, longFormatDetected: !!lfDet }).value || 'ordered';
  const results = await runFullAnalysis(
    matrix, rawMatrix, condCtx, assay, null, vst, {}, dataType, rowSemantics,
  );
  for (const r of results) {
    if (r.name in liveFlags) liveFlags[r.name][file] = r.flag;
  }
  if (!CHECK) process.stderr.write(' ok\n');
}

// ── Fires-on cell: presence from live output; mark via EXPECTED cross-ref ──
// A fire (live HIGH/MOD) that is in the fixture's EXPECTED.flags is credited —
// its tier label is the declared allow-set (singleton → HIGH/MOD; two-value →
// MOD/HIGH). A fire NOT in EXPECTED.flags is an acknowledged on-screen fire —
// its tier is the live flag, marked ` (ack)`. No fire anywhere → `— latent`.
function firesCell(name) {
  const parts = [];
  for (const [file, key] of FIXTURES) {
    const live = liveFlags[name][file];
    if (live !== 'HIGH' && live !== 'MODERATE') continue;
    const allow = EXPECTED[file]?.flags?.[name];
    if (allow) {
      parts.push(`${key} ${allow.map(f => SHORT[f]).join('/')}`);
    } else {
      parts.push(`${key} ${SHORT[live]} (ack)`);
    }
  }
  return parts.length ? parts.join(', ') : '— latent';
}

// ── Assemble the document ──
const sha = execSync('git rev-parse HEAD', { encoding: 'utf-8' }).trim();
const shortSha = sha.slice(0, 7);
const branch = execSync('git rev-parse --abbrev-ref HEAD', { encoding: 'utf-8' }).trim();
const now = new Date().toISOString().replace('T', ' ').slice(0, 19) + 'Z';

const lines = [];

// Title + GENERATED banner + provenance block.
lines.push('# Test → fixture lookup');
lines.push('');
lines.push('**GENERATED — DO NOT HAND-EDIT** — regenerate via');
lines.push('`node scripts/build-test-display-map.mjs`');
lines.push('');
lines.push(`- Generated: ${now}`);
lines.push(`- Commit:    \`${shortSha}\` (\`${sha}\`)`);
lines.push(`- Branch:    \`${branch}\``);
lines.push('- Batch:     live `result.flag` via the validate-batch pipeline over the shared 22-fixture set (`test/batch-fixtures.mjs`)');
lines.push('');

// Purpose line (kept from the hand-built file).
lines.push('Answers one question for the visual walk: **which dataset do I load to see a');
lines.push('visible flag for test X.**');
lines.push('');

// Source basis.
lines.push('## Source basis');
lines.push('');
lines.push('Every cell is derived from source, not transcribed from any prior version of');
lines.push('this file:');
lines.push('');
lines.push('- **Code test name** — the canonical key of `TEST_MECHANISM` in');
lines.push('  `src/constants/mechanisms.js`. This is the engine `result.name`, shared by');
lines.push('  the dispatch maps.');
lines.push('- **UI name** — the `DISPLAY_NAMES` value for that key');
lines.push('  (`src/constants/mechanisms.js`).');
lines.push('- **Cluster** — the §3 display category. `TEST_MECHANISM[name]` gives the');
lines.push('  internal key (`copied` / `digits` / `shapes` / `replicate` / `group`); the');
lines.push('  display name is `MECHANISMS[key].label`.');
lines.push('- **Fires on** — presence from live batch output: a test appears under a');
lines.push('  fixture when its `result.flag` is HIGH or MOD there. The mark is set by');
lines.push('  cross-referencing the shared `EXPECTED` allow-sets in');
lines.push('  `test/batch-fixtures.mjs` — a fire declared in that fixture\'s');
lines.push('  `EXPECTED.flags` is credited (bare); a fire that renders but is not a');
lines.push('  declared channel is acknowledged (`(ack)`).');
lines.push('');
lines.push('**Tier rendering.** Credited fires take the declared allow-set: a singleton');
lines.push('`[\'HIGH\']` renders `HIGH`, and a two-value `[\'MODERATE\',\'HIGH\']` renders');
lines.push('`MOD/HIGH` (the fixture permits either tier). Acknowledged fires take the live');
lines.push('tier — `HIGH` or `MOD` — followed by `(ack)`. A test with no fire on any');
lines.push('fixture is `— latent`.');
lines.push('');
lines.push('Sorted by cluster in fixed display order (copied → digits → shapes → replicate');
lines.push('→ group); tests alphabetical by UI name within each cluster.');
lines.push('');

// Lookup table — five per-cluster sections.
lines.push('## Lookup table');
lines.push('');
for (const mk of MECHANISM_ORDER) {
  const tests = Object.keys(TEST_MECHANISM)
    .filter(name => TEST_MECHANISM[name] === mk)
    .sort((a, b) => (DISPLAY_NAMES[a] || a).localeCompare(DISPLAY_NAMES[b] || b));
  lines.push(`### ${CLUSTER_TITLE[mk]}`);
  lines.push('');
  lines.push('| Code test name | UI name | Cluster | Fires on |');
  lines.push('|---|---|---|---|');
  for (const name of tests) {
    lines.push(`| ${name} | ${DISPLAY_NAMES[name] || name} | ${CLUSTER_TITLE[mk]} | ${firesCell(name)} |`);
  }
  lines.push('');
}

// Legend.
lines.push('Credited fires are unmarked; `(ack)` marks a fire that renders on screen but is not a declared detection channel for that fixture (incidental or corroborating — see TEST-GROUND-TRUTH for the per-fixture rationale).');
lines.push('');

// Notes.
lines.push('## Notes');
lines.push('');
lines.push('- 28 active tests, matching the 28 keys of `TEST_MECHANISM`.');
lines.push('- Seven tests are `— latent`: no fixture in `EXPECTED` declares a HIGH or MOD');
lines.push('  allow-set for them, and they carry no acknowledged fire. They are Decimal');
lines.push('  Precision Consistency, Distinct numbers (Entropy / Zipf), Number of peaks');
lines.push('  (Modality), Local noise correlation (Windowed Autocorrelation), Noise');
lines.push('  distribution (Excess Kurtosis), Within-row noise (Within-Row Variance), and');
lines.push('  Cross-Condition Rank Correlation.');
lines.push('- The acknowledged fires come from the `ACKNOWLEDGED` side-map in');
lines.push('  `test/batch-fixtures.mjs`, which holds two entries: Mahalanobis Row Outlier');
lines.push('  on DS06 (HIGH) and DS08 (MOD), both incidental single-row outliers downstream');
lines.push('  of other manipulations. Tiers are the live engine flag on those two');
lines.push('  fixtures; the side-map itself stores a reason string, not a tier.');
lines.push('- DS12b is the fabricated half of the uniform-mixture pair (file');
lines.push('  `12b-uniform-mixture-fabricated.csv`); DS12a is clean and carries no flags.');

const out = lines.join('\n') + '\n';

// ── --check: diff table/legend/notes against the committed doc ──
// Ignore the provenance block (timestamp + SHA change every run), so a stale
// table — not a fresh commit — is what trips the check.
function stripProvenance(text) {
  return text
    .split('\n')
    .filter(l => !/^- (Generated|Commit|Branch|Batch):/.test(l))
    .join('\n');
}

if (CHECK) {
  let committed = '';
  try {
    committed = readFileSync(OUT_PATH, 'utf-8');
  } catch {
    console.error(`map is stale — ${OUT_PATH} missing; regenerate via node scripts/build-test-display-map.mjs`);
    process.exit(1);
  }
  if (stripProvenance(committed) !== stripProvenance(out)) {
    console.error('map is stale — regenerate via node scripts/build-test-display-map.mjs');
    process.exit(1);
  }
  process.exit(0);
}

writeFileSync(OUT_PATH, out);
process.stderr.write(`\nWrote ${OUT_PATH} — ${Object.keys(TEST_MECHANISM).length} tests, ${FIXTURES.length} fixtures.\n`);
